@exercises wiringManager (wm)
@surface   wm:load, wm:instantiateFxOnScratch, wm:mutate, wm:enableLive, wm:diff, wm:targetState, wm:snapshot, wm:graph, wm:fastGainCommit, wm:reconcile, wm:syncExternal
