  @case 'model stays truthful: a fresh snapshot still equals target after a mint+apply'  [harness]  @ 88-96
  @case 'fastGainCommit mirrors into the model: a follow-up reconcile re-issues no gain write'  [harness]  @ 99-114
  @case 'syncExternal invalidates the model → next reconcile reads'  [harness]  @ 117-127
  @case 'load invalidates the model → reconcile reads REAPER, not stale intent'  [harness]  @ 130-139

